using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Keep the old name so existing documents (and direct SQL queries filtering on
        // c.Discriminator) continue to work without a data migration.
        modelBuilder.HasEmbeddedDiscriminatorName("Discriminator");

        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF Core 9 no longer includes the discriminator in the JSON "id" value.
            // Existing documents use the EF Core 8 format "Product|123", so opt back in
            // to avoid a full data migration of 500K documents.
            b.HasDiscriminatorInJsonId();
        });

        // HasIndex was removed — the Cosmos provider now throws because Cosmos DB does
        // not support secondary indexes defined through EF Core.
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

